+            entry.scenario_id
+        );
+    }
+    assert!(
+        report
+            .entries
+            .iter()
+            .any(|entry| entry.recommendation == "accept"),
+        "scorecard must include acceptance path"
+    );
+    assert!(
+        report
+            .entries
+            .iter()
+            .any(|entry| entry.recommendation == "rollback"),
